  ('f2000000-0000-4000-8000-000000000009', 'f1000000-0000-4000-8000-000000000005', 'to1', 60, 'Осмотр горелки и подачи газа; чистка сопел; проверка кабелей и шлангов; контроль заземления'),
  ('f2000000-0000-4000-8000-000000000010', 'f1000000-0000-4000-8000-000000000005', 'to2', 365, 'Ревизия редуктора робота; замена изоляции; калибровка траектории; проверка блокировок'),
